//go:build vectors

package server

import (
	"context"
	"log/slog"
	"time"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"
	"github.com/a<HOME>/agentic-rag-mcp/internal/ingest"
	"github.com/a<HOME>/agentic-rag-mcp/internal/search"

	"github.com/modelcontextprotocol/go-sdk/mcp"
)

// Server wraps the MCP server with knowledge intelligence tools.
type Server struct {
	mcp      *mcp.Server
	pipeline *ingest.Pipeline
	searcher *search.Searcher
	embedder embedder.Embedder
	cfg      config.Config
	started  time.Time
}

// New creates a new knowledge MCP server.
func New(
	pipeline *ingest.Pipeline,
	searcher *search.Searcher,
	emb embedder.Embedder,
	cfg config.Config,
) *Server {
	s := &Server{
		mcp: mcp.NewServer(
			&mcp.Implementation{
				Name:    "knowledge-mcp",
				Version: "0.1.0",
			},
			nil,
		),
		pipeline: pipeline,
		searcher: searcher,
		embedder: emb,
		cfg:      cfg,
		started:  time.Now(),
	}

	s.registerTools()
	return s
}

// Run starts the MCP server on stdio transport.
func (s *Server) Run(ctx context.Context) error {
	slog.Info("starting knowledge MCP server",
		"name", "knowledge-mcp",
		"version", "0.1.0",
	)
	return s.mcp.Run(ctx, &mcp.StdioTransport{})
}

// Uptime returns the server's uptime.
func (s *Server) Uptime() time.Duration {
	return time.Since(s.started)
}
